import nltk
nltk.download('all')

from nltk.tokenize import word_tokenize

from wordcloud import WordCloud
from matplotlib import pyplot as plt

def wordcloud_plot(counter_all):

  w= WordCloud().generate_from_frequencies(frequencies =dict(counter_all))
  plt.imshow(w)



def tokenize(text):
  tokens =[w for w in word_tokenize(text.lower())]
  return tokens

counter_all =Counter(flatten(rd["reviewText"].apply(tokenize).tolist()))

counter_all.most_common(10)

wordcloud_plot(counter_all)



"""the 10 most commom words seem to all be stop words and/or punctuations

**wt if we remove stopords**
"""

from nltk.corpus import stopwords
english_stopwords = set(stopwords.words('english'))

def tokenize_clean(text):
  tokens = [w for w in word_tokenize(text.lower()) if w not in english_stopwords]
  return tokens

counter_all =Counter(flatten(rd["reviewText"].apply(tokenize_clean).tolist()))

counter_all.most_common(10)

wordcloud_plot(counter_all)

