def get_noun_phrases(text):
  doc = nlp(text)
  required_nc = []
  for c in doc.noun_chunks:
    new_nc = [t.text for t in c if t.pos_ in ["NOUN","PROPN"]]
    if new_nc:
      # Corrected line: use the string's join method
      new_nc_text = " ".join(new_nc)
      required_nc.append(new_nc_text)
  # The original code had `return required_nc` inside the loop,
  # which would cause it to return after processing only the first noun chunk.
  # Moving it outside the loop to process all noun chunks.
  return required_nc

from tqdm.auto import tqdm
tqdm.pandas()

rd["noun_phrases"] = rd["reviewText"].progress_apply(get_noun_phrases)

